#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 100005

char *words[MAXN];
int used[MAXN];

int cmp_desc(const void *a, const void *b) {
    char *s1 = *(char **)a;
    char *s2 = *(char **)b;
    return strlen(s2) - strlen(s1);
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N;
        scanf("%d", &N);

        int maxLen = 0;

        for (int i = 0; i < N; i++) {
            words[i] = malloc(100005);
            scanf("%s", words[i]);
            used[i] = 0;

            int len = strlen(words[i]);
            if (len > maxLen) maxLen = len;
        }

        long long answer = 0;

        // Process from largest possible d
        for (int d = maxLen; d >= 1; d--) {

            for (int i = 0; i < N; i++) {
                if (used[i]) continue;
                if ((int)strlen(words[i]) < d) continue;

                for (int j = i + 1; j < N; j++) {
                    if (used[j]) continue;
                    if ((int)strlen(words[j]) < d) continue;

                    // check prefix
                    if (strncmp(words[i], words[j], d) != 0)
                        continue;

                    // check suffix
                    int li = strlen(words[i]);
                    int lj = strlen(words[j]);

                    if (strncmp(words[i] + li - d,
                                words[j] + lj - d, d) != 0)
                        continue;

                    used[i] = used[j] = 1;
                    answer += 1LL * d * d;
                    break;
                }
            }
        }

        printf("%lld\n", answer);

        for (int i = 0; i < N; i++)
            free(words[i]);
    }

    return 0;
}

