import java.io.*;
import java.util.*;

public class Main {

    static class FastScanner {
        BufferedReader br;
        StringTokenizer st;
        FastScanner(InputStream is) {
            br = new BufferedReader(new InputStreamReader(is));
        }
        String next() throws IOException {
            while (st == null || !st.hasMoreTokens())
                st = new StringTokenizer(br.readLine());
            return st.nextToken();
        }
        int nextInt() throws IOException {
            return Integer.parseInt(next());
        }
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder output = new StringBuilder();
        int T = fs.nextInt();

        while (T-- > 0) {
            int N = fs.nextInt();
            String[] words = new String[N];
            int maxLen = 0;

            for (int i = 0; i < N; i++) {
                words[i] = fs.next();
                maxLen = Math.max(maxLen, words[i].length());
            }

            boolean[] used = new boolean[N];
            long answer = 0;

            // process from largest possible d to smallest
            for (int d = maxLen; d >= 1; d--) {

                Map<String, List<Integer>> map = new HashMap<>();

                for (int i = 0; i < N; i++) {
                    if (used[i]) continue;

                    String w = words[i];
                    if (w.length() < d) continue;

                    String key = w.substring(0, d) + "#" +
                                 w.substring(w.length() - d);

                    map.computeIfAbsent(key, k -> new ArrayList<>()).add(i);
                }

                for (List<Integer> list : map.values()) {
                    for (int i = 0; i + 1 < list.size(); i += 2) {
                        int a = list.get(i);
                        int b = list.get(i + 1);

                        if (!used[a] && !used[b]) {
                            used[a] = true;
                            used[b] = true;
                            answer += 1L * d * d;
                        }
                    }
                }
            }

            output.append(answer).append("\n");
        }

        System.out.print(output);
    }
}
